class Solution:
    def makeSubKSumEqual(self, arr, k):
        n = len(arr)
        visited = [False] * n
        total = 0
        for start in range(n):
            if visited[start]:
                continue
            group = []
            i = start
            while not visited[i]:
                visited[i] = True
                group.append(arr[i])
                i = (i + k) % n
            best = None
            for cand in group:
                cost = sum(abs(x - cand) for x in group)
                if best is None or cost < best:
                    best = cost
            total += best
        return total

