function _gcd(a, b) {
    while (b) {
        const t = a % b;
        a = b;
        b = t;
    }
    return a;
}
var makeSubKSumEqual = function(arr, k) {
    const n = arr.length;
    const g = _gcd(n, k);
    let total = 0;
    for (let r = 0; r < g; r++) {
        const group = [];
        for (let i = r; i < n; i += g) group.push(arr[i]);
        group.sort((a, b) => a - b);
        const median = group[Math.floor(group.length / 2)];
        for (const x of group) total += Math.abs(x - median);
    }
    return total;
};
